parameters.jsCode:
const output = $input.first().json.stdout || '';
const exitCode = $input.first().json.exitCode;
const success = exitCode === 0;

return [{
  json: {
    timestamp: new Date().toISOString(),
    success: success,
    exitCode: exitCode,
    output: output.substring(0, 500),
    needsAlert: !success
  }
}];

parameters.message:
=Daily backup failed at {{ $json.timestamp }}.

Exit code: {{ $json.exitCode }}
Output: {{ $json.output }}

Please check the backup system.
